// ── Protocol types (generated by ts-rs from Rust source) ─────────────

import type { ImageAttachment as _ImageAttachment } from "./generated/protocol";
export type { ClientMessage, ServerMessage, ImageAttachment } from "./generated/protocol";

// Local alias for use within this file
type ImageAttachment = _ImageAttachment;

// ── Chat history ─────────────────────────────────────────────────────

export interface ToolCallRecord {
  id: string;
  name: string;
  arguments: string;
}

export interface RecentMessage {
  role: "user" | "assistant" | "tool" | "system";
  content: string;
  tool_calls?: ToolCallRecord[];
  tool_call_id?: string;
  timestamp: string;
  project_context: string;
  visibility: "user" | "background";
}

// ── Chat history segments (paginated lazy-load) ──────────────────────

export interface RecentHistorySegment {
  kind: "recent";
  messages: RecentMessage[];
  next_cursor: string | null;
}

export interface EpisodeHistorySegment {
  kind: "episode";
  episode_id: string;
  date: string; // YYYY-MM-DD
  context: string;
  messages: RecentMessage[];
  next_cursor: string | null;
}

export type ChatHistorySegment = RecentHistorySegment | EpisodeHistorySegment;

// ── Status API ───────────────────────────────────────────────────────

export interface StatusResponse {
  mode: "setup" | "running";
}

