// ── Feed items (UI rendering) ────────────────────────────────────────

export type ConnectionStatus = "connecting" | "connected" | "disconnected";

export interface ToolCallState {
  id: string;
  name: string;
  arguments: Record<string, unknown>;
  status: "running" | "done" | "error";
  result?: string;
}

interface FeedItemBase {
  id: number;
}

export interface UserFeedItem extends FeedItemBase {
  kind: "user";
  content: string;
  images?: ImageAttachment[];
}

export interface AssistantFeedItem extends FeedItemBase {
  kind: "assistant";
  content: string;
}

export interface DividerFeedItem extends FeedItemBase {
  kind: "divider";
  label: string;
  variant?: "episode" | "day";
}

export interface CompressedMarkerFeedItem extends FeedItemBase {
  kind: "compressed-marker";
}

export interface ToolGroupFeedItem extends FeedItemBase {
  kind: "tool-group";
  calls: ToolCallState[];
}

export interface FileAttachmentFeedItem extends FeedItemBase {
  kind: "file-attachment";
  filename: string;
  mimeType: string;
  size: number;
  url: string;
  caption: string | null;
}

/**
 * Client-originated, ephemeral system text rendered inline in the chat
 * stream. Used for slash command output (`/help`, `/status`, `/context`)
 * that the user wants to read carefully but should not persist across
 * reloads or land in conversation history.
 */
export interface LocalSystemFeedItem extends FeedItemBase {
  kind: "local-system";
  content: string;
}

export type FeedItem =
  | UserFeedItem
  | AssistantFeedItem
  | DividerFeedItem
  | CompressedMarkerFeedItem
  | ToolGroupFeedItem
  | FileAttachmentFeedItem
  | LocalSystemFeedItem;

// ── User Inbox ───────────────────────────────────────────────────────

export interface UserInboxItem {
  id: string;
  title: string;
  body: string;
  source: string;
  timestamp: string;
  read: boolean;
  attachments: string[];
}
